1	package cli
2	
3	import (
4		"errors"
5		"fmt"
6		"os"
7		"path/filepath"
8		"time"
9	
10		"github.com/spf13/cobra"
11	
12		"github.com/agent-sync/agent-sync/internal/engine"
13		"github.com/agent-sync/agent-sync/internal/fsroot"
14		"github.com/agent-sync/agent-sync/internal/report"
15	)
16	
17	// hookSkippedMarker records that a git-hook-driven sync yielded to an
18	// in-progress manual sync (so it never breaks `git pull`).
19	const hookSkippedMarker = ".agent-sync/state/hook-skipped"
20	
21	// postMergeRunLockTimeout caps how long a --post-merge (git-hook) sync waits
22	// for the per-workspace run lock before yielding a blocked result and exiting
23	// 0. Short so a contended `git pull` is never stalled by the default multi-minute
24	// wait.
25	const postMergeRunLockTimeout = 3 * time.Second
26	
27	func newSyncCommand(deps RootDeps) *cobra.Command {
28		var (
29			bestEffort      bool
30			adoptPrefixes   []string
31			targetFilter    []string
32			expectDeletions int
33			postMerge       bool
34			userScope       bool
35		)
36	
37		cmd := &cobra.Command{
38			Use:   "sync",
39			Short: "Sync target tools from the canonical manifest",
40			Long: "Materialize the canonical source, run each target's adapter, and " +
41				"atomically write the resulting configuration into the workspace.",
42			SilenceUsage:  true,
43			SilenceErrors: true,
44			RunE: func(cmd *cobra.Command, _ []string) error {
45				rc, err := mustRuntime(cmd)
46				if err != nil {
47					return err
48				}
49				now := deps.now()()
50	
51				opts := engine.Options{
52					AdoptPrefixes: adoptPrefixes,
53					TargetsFilter: targetFilter,
54					Now:           func() time.Time { return now },
55					Logger:        rc.Logger,
56				}
57				if bestEffort {
58					opts.Mode = report.ModeBestEffort
59				} else {
60					opts.Mode = report.ModeAtomic
61				}
62				if cmd.Flags().Changed("expect-deletions") {
63					opts.ExpectDeletions = &expectDeletions
64				}
65				if postMerge {
66					// A git-hook sync must yield fast to a manual sync rather than
67					// stall `git pull`: cap the run-lock wait so contention becomes a
68					// quick blocked-and-yield (exit 0) instead of the multi-minute
69					// default. The engine reports blocked targets; the post-merge
70					// handlers below turn that into a clean exit 0.
71					opts.RunLockTimeout = postMergeRunLockTimeout
72				}
73	
74				// An explicit --workspace override pins a single scope and disables
75				// hierarchy discovery (today's behavior wins). --user is meaningless
76				// then: it selects the user scope of a discovered hierarchy.
77				if rc.Flags.Workspace != "" {
78					if userScope {
79						return errUserWithWorkspace
80					}
81					return runSingleScopeSync(cmd, rc, opts, postMerge, now)
82				}
83	
84				// Hierarchy path: discover every emit scope from cwd and sync each.
85				cwd, err := os.Getwd()
86				if err != nil {
87					return fmt.Errorf("sync: resolve cwd: %w", err)
88				}
89				home, err := resolveHome()
90				if err != nil {
91					return fmt.Errorf("sync: %w", err)
92				}
93				outcomes, notice, err := runHierarchySync(cmd.Context(), rc, cwd, home,
94					hierarchySyncOptions{IncludeUser: userScope, EngineOpts: opts}, now)
95				if err != nil {
96					return fmt.Errorf("sync: %w", err)
97				}
98	
99				// Post-merge hook mode: if any scope was blocked by an in-progress
100				// sync's lock, write that scope's skip marker and exit 0 so
101				// `git pull` is never broken (plan U3 / AGENTS invariant #3 spirit).
102				if postMerge {
103					if handled := handleHierarchyPostMerge(rc, outcomes, now); handled {
104						return nil
105					}
106				}
107	
108				if rc.Access.Output == OutputJSON {
109					if err := renderHierarchyJSON(cmd.OutOrStdout(), outcomes, notice); err != nil {
110						return err
111					}
112				} else if err := renderHierarchyText(cmd.OutOrStdout(), outcomes, notice); err != nil {
113					return err
114				}
115				if code := hierarchyExitCode(outcomes); code != 0 {
116					return &exitError{code: code, err: errors.New("sync reported failures")}
117				}
118				return nil
119			},
120		}
121	
122		cmd.Flags().BoolVar(&bestEffort, "best-effort", false, "continue past a failing target instead of aborting the run")
123		cmd.Flags().StringArrayVar(&adoptPrefixes, "adopt-prefix", nil, "adopt pre-existing unmanaged content under this reserved prefix")
124		cmd.Flags().StringArrayVar(&targetFilter, "target", nil, "restrict the sync to these target names (repeatable)")
125		cmd.Flags().IntVar(&expectDeletions, "expect-deletions", 0, "abort unless exactly this many files would be deleted")
126		cmd.Flags().BoolVar(&postMerge, "post-merge", false, "git-hook mode: yield to an in-progress sync and exit 0")
127		cmd.Flags().BoolVar(&userScope, "user", false, "also sync the user-level (~) manifest")
128		return cmd
129	}
130	
131	// runSingleScopeSync runs the legacy single-scope sync against the nearest
132	// (or explicit --workspace) scope. It preserves today's behavior verbatim and
133	// is taken only when an explicit --workspace override is in effect; the
134	// default path is the hierarchy orchestrator. validate also relies on this
135	// single-scope shape via prepareEngine.
136	func runSingleScopeSync(cmd *cobra.Command, rc *runtimeContext, opts engine.Options, postMerge bool, now time.Time) error {
137		prep, err := prepareEngine(cmd.Context(), rc, now)
138		if err != nil {
139			return fmt.Errorf("sync: %w", err)
140		}
141		defer prep.Close()
142	
143		req := prep.Request
144		req.Options = opts
145	
146		root := prep.Root
147		summary, err := engine.Sync(cmd.Context(), req)
148		if err != nil {
149			return fmt.Errorf("sync: %w", err)
150		}
151	
152		// Post-merge hook mode: if a target was blocked by an in-progress sync's
153		// lock, write the skip marker and exit 0 so `git pull` is never broken
154		// (plan U3 / AGENTS invariant #3 spirit).
155		if postMerge && anyBlocked(summary) {
156			if werr := writeHookSkipped(root, now); werr != nil {
157				rc.Logger.Warn("sync: failed to write hook-skipped marker", "err", werr)
158			}
159			return nil
160		}
161	
162		if err := renderSummary(cmd, rc.Access, summary); err != nil {
163			return err
164		}
165		if summary.Outcome.ExitCode != 0 {
166			return &exitError{code: summary.Outcome.ExitCode, err: errors.New("sync reported failures")}
167		}
168		return nil
169	}
170	
171	// handleHierarchyPostMerge applies the post-merge yield across the hierarchy:
172	// for each scope whose sync was blocked by an in-progress lock, it writes that
173	// scope's hook-skipped marker. It returns true when any scope was blocked, in
174	// which case the caller exits 0 so `git pull` is never broken. A blocked scope
175	// has no engine error (the lock yield is a clean outcome), so its summary is
176	// inspected via anyBlocked.
177	func handleHierarchyPostMerge(rc *runtimeContext, outcomes []scopeOutcome, now time.Time) bool {
178		handled := false
179		for _, o := range outcomes {
180			if o.Err != nil || !anyBlocked(o.Summary) {
181				continue
182			}
183			handled = true
184			root, err := fsroot.OpenWorkspaceRoot(o.Scope.Root)
185			if err != nil {
186				rc.Logger.Warn("sync: failed to open root for hook-skipped marker", "root", o.Scope.Root, "err", err)
187				continue
188			}
189			if werr := writeHookSkipped(root, now); werr != nil {
190				rc.Logger.Warn("sync: failed to write hook-skipped marker", "root", o.Scope.Root, "err", werr)
191			}
192			_ = root.Close()
193		}
194		return handled
195	}
196	
197	func anyBlocked(s report.Summary) bool {
198		for _, t := range s.Targets {
199			if t.Status == report.StatusBlocked {
200				return true
201			}
202		}
203		return false
204	}
205	
206	func writeHookSkipped(root *fsroot.Root, now time.Time) error {
207		if err := root.Inner().MkdirAll(filepath.Dir(hookSkippedMarker), 0o755); err != nil {
208			return err
209		}
210		return root.StagedWrite(hookSkippedMarker, []byte(now.UTC().Format(time.RFC3339)+"\n"), 0o644)
211	}
212	
213	// renderSummary writes the report to stdout as text or JSON per the
214	// resolved Access; logs and banners go to stderr (the logger), data to
215	// stdout.
216	func renderSummary(cmd *cobra.Command, access Access, summary report.Summary) error {
217		if access.Output == OutputJSON {
218			data, err := report.MarshalJSON(summary)
219			if err != nil {
220				return fmt.Errorf("sync: marshal json: %w", err)
221			}
222			_, err = fmt.Fprintln(cmd.OutOrStdout(), string(data))
223			return err
224		}
225		_, err := fmt.Fprint(cmd.OutOrStdout(), report.RenderText(summary))
226		return err
227	}
228

